# Basic try-except block
number = 10
try:
    result = number / 0
except ZeroDivisionError:
    print('Error: Division by zero!')

# Common error types
try:
    number = '10' + 5  # TypeError
except TypeError:
    print('Error: Type mismatch!')

try:
    number = int('abc')  # ValueError
except ValueError:
    print('Error: Invalid value!')

try:
    result = 10 / 0  # ZeroDivisionError
except ZeroDivisionError:
    print('Error: Division by zero!')

try:
    my_list = [1, 2, 3]
    print(my_list[10])  # IndexError
except IndexError:
    print('Error: Index out of range!')

# Try-except-else
try:
    number = 10
    result = number / 2
except ZeroDivisionError:
    print('Error: Division by zero!')
else:
    print(f'Result: {result}')

# Handling multiple exceptions
try:
    my_list = [1, 2, 3]
    result = my_list[10] / int('abc')
except (IndexError, ValueError, ZeroDivisionError) as e:
    print(f'Error: {e}')

# Custom exception
class CustomError(Exception):
    pass

try:
    number = -5
    if number < 0:
        raise CustomError('Negative number entered!')
except CustomError as e:
    print(f'Error: {e}')

# Exceptions in for loop
numbers = [1, 2, 0, 4, 5]
for num in numbers:
    try:
        result = 10 / num
        print(f'Result: {result}')
    except ZeroDivisionError:
        print('Error: Division by zero!')

# Exceptions in while loop
count = 3
while count >= 0:
    try:
        result = 10 / count
        print(f'Result: {result}')
    except ZeroDivisionError:
        print('Error: Division by zero!')
    count -= 1

# Python code
try:
    result = 10 / 0
except ZeroDivisionError:
    print('Error: Division by zero!')

