    number = '10' + 5  # TypeError
except TypeError:
    print('Ошибка: Несоответствие типов!')

try:
    number = int('abc')  # ValueError
except ValueError:
    print('Ошибка: Недопустимое значение!')

try:
    result = 10 / 0  # ZeroDivisionError
except ZeroDivisionError:
    print('Ошибка: Деление на ноль!')

try:
    my_list = [1, 2, 3]
    print(my_list[10])  # IndexError
except IndexError:
    print('Ошибка: Индекс вне диапазона!')

# Try-except-else
