    number = 10
    result = number / 2
except ZeroDivisionError:
    print('Ошибка: Деление на ноль!')
else:
    print(f'Результат: {result}')

# Обработка нескольких исключений
try:
    my_list = [1, 2, 3]
    result = my_list[10] / int('abc')
except (IndexError, ValueError, ZeroDivisionError) as e:
    print(f'Ошибка: {e}')

