for num in numbers:
    try:
        result = 10 / num
        print(f'Результат: {result}')
    except ZeroDivisionError:
        print('Ошибка: Деление на ноль!')

# Исключения в цикле while
count = 3
while count >= 0:
    try:
        result = 10 / count
        print(f'Результат: {result}')
    except ZeroDivisionError:
        print('Ошибка: Деление на ноль!')
    count -= 1

